// Extract Notion iframe URL from CS Insider page
const html = $input.first().json.content || '';

// Look for Notion iframe src
const iframeMatch = html.match(/iframe[^>]+src="(https:\/\/csinsider\.notion\.site[^"]+)"/i);

if (!iframeMatch) {
  // Fallback: look for any notion.site URL
  const notionMatch = html.match(/https:\/\/csinsider\.notion\.site\/[a-f0-9]+/i);
  if (notionMatch) {
    return [{ json: { notionUrl: notionMatch[0] } }];
  }
  throw new Error('Could not find Notion iframe URL on CS Insider page');
}

// Clean up the URL (remove /ebd// prefix if present)
let notionUrl = iframeMatch[1];
notionUrl = notionUrl.replace('/ebd//', '/').replace(/\/+/g, '/');
notionUrl = notionUrl.replace('https:/', 'https://');

console.log('Found Notion URL:', notionUrl);

return [{ json: { notionUrl: notionUrl } }];

// Parse CS Insider Notion job board
const html = $input.first().json.content || '';

const jobs = [];

// Extract company names
const companyRegex = /Company<\/span>:\s*([^<]+)/gi;
const companyMatches = [];
let companyMatch;
while ((companyMatch = companyRegex.exec(html)) !== null) {
  companyMatches.push(companyMatch[1].trim());
}

// Extract locations
const locationRegex = /Location<\/span>:\s*([^<]+)/gi;
const locationMatches = [];
let locationMatch;
while ((locationMatch = locationRegex.exec(html)) !== null) {
  locationMatches.push(locationMatch[1].trim());
}

// Extract apply links (Greenhouse, Lever, etc.)
const applyRegex = /href="(https:\/\/[^"]*(?:greenhouse|lever|workday|jobs\.lever|boards\.greenhouse|careers|apply)[^"]*)"/gi;
const applyMatches = [];
let applyMatch;
while ((applyMatch = applyRegex.exec(html)) !== null) {
  const url = applyMatch[1];
  // Skip Notion internal links and duplicates
  if (!url.includes('notion.') && !applyMatches.includes(url)) {
    applyMatches.push(url);
  }
}

// Extract job titles from content-editable divs
const cleanTitles = [];
const titleCleanRegex = />([^<]*(?:Customer Success|CSM|Client Success|Account Manager|Success Manager|Engagement Manager)[^<]*)<\/div>/gi;
let titleCleanMatch;
while ((titleCleanMatch = titleCleanRegex.exec(html)) !== null) {
  const title = titleCleanMatch[1].trim();
  if (title.length > 5 && title.length < 100 && !cleanTitles.includes(title)) {
    cleanTitles.push(title);
  }
}

// Build job objects - only include jobs with URLs
const numJobs = applyMatches.length;

for (let i = 0; i < numJobs; i++) {
  const company = companyMatches[i];
  const title = cleanTitles[i];
  const jobUrl = applyMatches[i];

  // Only include if we have a URL and company
  if (jobUrl && company) {
    jobs.push({
      json: {
        'Job Title': title || 'Customer Success Manager',
        'Company': company,
        'Location': locationMatches[i] || 'Remote',
        'Job URL': jobUrl,
        'Source': 'CS Insider'
      }
    });
  }
}

console.log('=== CS INSIDER SCRAPE SUMMARY ===');
console.log('Jobs with URLs:', jobs.length);
console.log('Total companies found:', companyMatches.length);
console.log('Total apply links:', applyMatches.length);
console.log('Skipped (no URL):', companyMatches.length - jobs.length);

if (jobs.length === 0) {
  return [{
    json: {
      error: 'No jobs parsed',
      debug: {
        titlesFound: cleanTitles.length,
        companiesFound: companyMatches.length,
        sampleCompanies: companyMatches.slice(0, 10),
        sampleTitles: cleanTitles.slice(0, 10),
        applyLinksFound: applyMatches.length
      }
    }
  }];
}

return jobs;
